typedef struct tagMIXERCONTROLA {   DWORD cbStruct;
DWORD dwControlID;   DWORD dwControlType;   DWORD fdwControl;
DWORD cMultipleItems;
CHAR  szShortName[MIXER_SHORT_NAME_CHARS];
CHAR  szName[MIXER_LONG_NAME_CHARS];   union {
struct {
LONG lMinimum;       LONG lMaximum;     } DUMMYSTRUCTNAME;     struct {
DWORD dwMinimum;       DWORD dwMaximum;     } DUMMYSTRUCTNAME2;     DWORD dwReserved[6];
} Bounds;   union {
DWORD cSteps;
DWORD cbCustomData;     DWORD dwReserved[6];   } Metrics;
} MIXERCONTROLA, *PMIXERCONTROLA, *LPMIXERCONTROLA;
成员 cbStruct
MIXERCONTROL 结构的大小（以字节为单位）。 dwControlID
唯一引用 MIXERCONTROL 结构描述的控件的音频混音器定义标识符。 此标识符可以采用混音器设备支持的任何格式。 应用程序应仅将此标识符用作抽象句柄。 单个混音器设备的两个控件都不能具有相同的控制标识符。
dwControlType
dwControlID中指定的标识符的控件的类。 应用程序必须使用此信息来显示用户输入的相应控件。 应用程序还可以基于控件类显示定制的图形，或在特定行上搜索特定控件类。 如果应用程序不知道控件类，则必须忽略此控件。 有八个控件类分类，每个分类有一个或多个标准控件类型：
名字

